const getDocumentFileNameFromValue = (value) => {
  const raw = String(value || '').trim();
  if (!raw) return '';

  const withoutQuery = raw.split('?')[0].split('#')[0];
  const segments = withoutQuery.split(/[\\/]/).filter(Boolean);
  const fileName = segments[segments.length - 1] || withoutQuery;

  try {
    return decodeURIComponent(fileName);
  } catch (_error) {
    return fileName;
  }
};

const formatHeldSecurityDocumentLabel = (documentName, documentUrl, fallbackLabel = 'Security document') => {
  const fileName =
    getDocumentFileNameFromValue(documentName) ||
    getDocumentFileNameFromValue(documentUrl);

  if (!fileName) return fallbackLabel;

  const baseName = fileName.replace(/\.[a-z0-9]{2,8}$/i, '');
  const compactBaseName = baseName.replace(/[^a-z0-9]/gi, '');
  const looksGenerated =
    /^\d{10,}$/.test(baseName) ||
    (compactBaseName.length >= 18 && /^[a-z0-9]+$/i.test(compactBaseName));

  if (looksGenerated) {
    return `Document #${compactBaseName.slice(-4).padStart(4, '0')}`;
  }

  if (fileName.length > 34) {
    return `${fileName.slice(0, 18)}...${fileName.slice(-10)}`;
  }

  return fileName;
};

const buildVehicleIssueResolutionNote = ({
  refundOutcome,
  refundAmount,
  refundStatus,
  refundDestination,
  vehicleAction,
  internalNote,
  customerMessage,
  rentalRefundSelected,
  depositRefundSelected,
  depositRefundAmount,
  refundSignedAt,
  refundSignatureUrl,
  depositRefundCompletedAt,
}) => {
  const trimmedInternalNote = String(internalNote || '').trim();
  const payload = {
    refundOutcome: String(refundOutcome || '').trim().toLowerCase(),
    refundAmount: Math.max(0, Number(refundAmount || 0) || 0),
    refundStatus: String(refundStatus || '').trim().toLowerCase(),
    refundDestination: String(refundDestination || '').trim().toLowerCase(),
    vehicleAction: String(vehicleAction || '').trim().toLowerCase(),
    customerMessage: String(customerMessage || '').trim(),
    rentalRefundSelected: Boolean(rentalRefundSelected),
    depositRefundSelected: Boolean(depositRefundSelected),
    depositRefundAmount: Math.max(0, Number(depositRefundAmount || 0) || 0),
    refundSignedAt: String(refundSignedAt || '').trim(),
    refundSignatureUrl: String(refundSignatureUrl || '').trim(),
    depositRefundCompletedAt: String(depositRefundCompletedAt || '').trim(),
  };

  return `${trimmedInternalNote}\n${VEHICLE_ISSUE_RESOLUTION_MARKER}${JSON.stringify(payload)}`.trim();
};

const parseVehicleIssueResolutionNote = (value) => {
  const text = typeof value === 'string' ? value : '';
  const markerIndex = text.indexOf(VEHICLE_ISSUE_RESOLUTION_MARKER);
  if (markerIndex === -1) return null;

  const internalNote = text.slice(0, markerIndex).trim();
  const rawPayload = text.slice(markerIndex + VEHICLE_ISSUE_RESOLUTION_MARKER.length).trim();

  try {
    const payload = JSON.parse(rawPayload);
    return {
      internalNote,
      refundOutcome: String(payload?.refundOutcome || '').trim().toLowerCase(),
      refundAmount: Math.max(0, Number(payload?.refundAmount || 0) || 0),
      refundStatus: String(payload?.refundStatus || '').trim().toLowerCase(),
      refundDestination: String(payload?.refundDestination || '').trim().toLowerCase(),
      vehicleAction: String(payload?.vehicleAction || '').trim().toLowerCase(),
      customerMessage: String(payload?.customerMessage || '').trim(),
      rentalRefundSelected: payload?.rentalRefundSelected !== false,
      depositRefundSelected: Boolean(payload?.depositRefundSelected),
      depositRefundAmount: Math.max(0, Number(payload?.depositRefundAmount || 0) || 0),
      refundSignedAt: String(payload?.refundSignedAt || '').trim(),
      refundSignatureUrl: String(payload?.refundSignatureUrl || '').trim(),
      depositRefundCompletedAt: String(payload?.depositRefundCompletedAt || '').trim(),
    };
  } catch {
    return {
      internalNote: text.trim(),
      refundOutcome: '',
      refundAmount: 0,
      refundStatus: '',
      refundDestination: '',
      vehicleAction: '',
      customerMessage: '',
      rentalRefundSelected: false,
      depositRefundSelected: false,
      depositRefundAmount: 0,
      refundSignedAt: '',
      refundSignatureUrl: '',
      depositRefundCompletedAt: '',
    };
  }
};
