const getRentalAttentionState = (rental, vehicleReport) => {
  const report = vehicleReport || rental?.vehicleReport || rental?.vehicle_report || null;
  const reportStatus = String(report?.status || '').toLowerCase();
  const snapshotStatus = String(rental?.linked_maintenance_status || '').toLowerCase();
  const hasMaintenanceLink = Boolean(
    report?.maintenance_id ||
    report?.maintenance?.id ||
    rental?.linked_maintenance_id
  );
  const isClosed = String(rental?.rental_status || '').toLowerCase() === 'completed' && (
    reportStatus === 'maintenance_completed' ||
    snapshotStatus === 'maintenance_completed'
  );
  const effectiveMaintenanceStatus = isClosed
    ? 'maintenance_completed'
    : (reportStatus || snapshotStatus);

  if (!report && !hasMaintenanceLink && !effectiveMaintenanceStatus) return null;

  if (isClosed) {
    return {
      status: 'maintenance_closed',
      text: tr('Maintenance Closed', 'Maintenance clôturée'),
      className: 'bg-slate-100 text-slate-800 border border-slate-300',
      detailText: tr(
        'This rental had a linked maintenance issue that was resolved after return',
        'Cette location avait un problème de maintenance lié qui a été résolu après le retour'
      ),
    };
  }

  if (
    hasMaintenanceLink ||
    ['maintenance_created', 'maintenance_in_progress', 'maintenance_completed'].includes(effectiveMaintenanceStatus)
  ) {
    return {
      status: 'under_maintenance',
      text: tr('Under Maintenance', 'En maintenance'),
      className: 'bg-orange-100 text-orange-800 border border-orange-200',
      detailText: tr('Vehicle report linked to Quad Maintenance', 'Rapport véhicule lié à la maintenance du quad'),
    };
  }

  const labels = {
    damage: tr('Damage Report Saved', 'Rapport de dommage enregistré'),
    accident: tr('Accident Report Saved', "Rapport d'accident enregistré"),
    mechanical_issue: tr('Mechanical Report Saved', 'Rapport mécanique enregistré'),
  };

  return {
    status: 'vehicle_report',
    text: labels[report.report_type] || tr('Vehicle Report Saved', 'Rapport véhicule enregistré'),
    className: 'bg-red-100 text-red-800 border border-red-200',
    detailText: tr(
      'Vehicle inspection report saved on this rental while the timer continues',
      "Rapport d'inspection véhicule enregistré sur cette location pendant que le minuteur continue"
    ),
  };
};

const getRentalKilometerPackage = (rental, packageDetails) => {
  if (!isPackagePricingEnabled(rental)) return null;

  const pkg = buildRentalBookedPackageSnapshot(rental, rental?.package || packageDetails);
  if (!pkg) return null;

  const hasLinkedPackage = Boolean(
    rental?.package_id ||
    rental?.selected_package_id ||
    rental?.package?.id ||
    pkg?.id ||
    rental?.package_name ||
    rental?.selected_package_name
  );
  const hasKmConfig =
    pkg.included_kilometers !== null && pkg.included_kilometers !== undefined ||
    pkg.extra_km_rate !== null && pkg.extra_km_rate !== undefined ||
    pkg.total_included_kilometers_snapshot !== null && pkg.total_included_kilometers_snapshot !== undefined;

  return hasLinkedPackage && hasKmConfig ? pkg : null;
};

const getPackageRentalDurationUnits = (rental = {}) => {
  if (!rental?.use_package_pricing) return null;

  const packageDuration = Number(
    rental?.package?.duration_units ??
    rental?.package_duration_units ??
    rental?.packageDurationUnits
  );

  return Number.isFinite(packageDuration) && packageDuration > 0 ? packageDuration : null;
};

const getRentalDurationUnits = (rental = {}) => {
  const actualDuration = rental?.rental_type === 'hourly'
    ? Number(rental?.quantity_hours ?? rental?.quantity_days)
    : Number(rental?.quantity_days);

  if (Number.isFinite(actualDuration) && actualDuration > 0) {
    return actualDuration;
  }

  const packageDuration = getPackageRentalDurationUnits(rental);
  if (packageDuration) return packageDuration;

  return 1;
};

const getRentalActualDurationUnits = (rental = {}) => {
  const actualDuration = String(rental?.rental_type || '').toLowerCase() === 'hourly'
    ? Number(rental?.quantity_hours ?? rental?.quantity_days)
    : Number(rental?.quantity_days);

  return Number.isFinite(actualDuration) && actualDuration > 0 ? actualDuration : null;
};

const getPackageDurationMultiplier = (rental = {}, pkg = null) => {
  const actualDuration = getRentalActualDurationUnits(rental) || getRentalDurationUnits(rental) || 1;
  const packageDuration = Number(
    pkg?.duration_units ??
    pkg?.duration ??
    rental?.package?.duration_units ??
    rental?.package_duration_units ??
    rental?.packageDurationUnits ??
    1
  );

  if (!Number.isFinite(actualDuration) || actualDuration <= 0) return 1;
  if (!Number.isFinite(packageDuration) || packageDuration <= 0) return actualDuration;

  return Math.max(1, actualDuration / packageDuration);
};

const getPackageRatePerUnit = (rental = {}, pkg = null) => {
  const resolvedPackage = pkg || getRentalKilometerPackage(rental);
  return Number.parseFloat(resolvedPackage?.fixed_amount || rental?.unit_price || 0) || 0;
};

const getPackageContractBaseTotal = (rental = {}, pkg = null, options = {}) => {
  const resolvedPackage = pkg || getRentalKilometerPackage(rental);
  if (!resolvedPackage) return 0;

  const preferPackageAmount = Boolean(options?.preferPackageAmount);
  const storedSnapshotAmount = Number.parseFloat(
    rental?.selected_package_fixed_amount ??
    rental?.package_rate_per_unit ??
    rental?.selected_package_rate_per_unit ??
    rental?.unit_price ??
    rental?.unit_price_mad ??
    0
  ) || 0;
  const packageAmount = Number.parseFloat(
    resolvedPackage?.fixed_amount ??
    resolvedPackage?.fixedAmount ??
    0
  ) || 0;

  if (preferPackageAmount && packageAmount > 0) {
    return Math.max(0, packageAmount);
  }

  return Math.max(0, storedSnapshotAmount || packageAmount);
};

const getPackageDisplayTotal = (rental = {}, pkg = null) => {
  const resolvedPackage = pkg || getRentalKilometerPackage(rental);
  if (!resolvedPackage) return 0;

  const packageRate = getPackageRatePerUnit(rental, resolvedPackage);
  if (!packageRate) return 0;

  return packageRate * getPackageDurationMultiplier(rental, resolvedPackage);
};

const getBookedPackageSnapshotTotal = (rental = {}, pkg = null) => {
  return getPackageContractBaseTotal(rental, pkg);
};

const getPackageIncludedKilometersPerUnit = (pkg = null) => Number.parseFloat(
  pkg?.included_kilometers ??
  pkg?.includedKilometers ??
  pkg?.included_km ??
  pkg?.includedKm ??
  0
) || 0;

const getPackageExpectedTotalIncludedKilometers = (rental = {}, pkg = null) => {
  const includedPerUnit = getPackageIncludedKilometersPerUnit(pkg);
  return includedPerUnit > 0
    ? includedPerUnit * getPackageDurationMultiplier(rental, pkg)
    : 0;
};

const getStoredBookedPackageTotalIncludedKilometers = (rental = {}, pkg = null) => {
  const storedIncludedKmCandidates = [
    pkg?.total_included_kilometers_snapshot,
    rental?.package_total_included_km,
    rental?.selected_package_total_included_km,
    rental?.included_kilometers,
  ]
    .map((value) => Number.parseFloat(value))
    .filter((value) => Number.isFinite(value) && value > 0);

  return storedIncludedKmCandidates[0] || 0;
};

const getRentalHourlyRate = (rental = {}) => {
  const directVehicleHourlyRate = Number(
    rental?.vehicle?.hourly_rate ??
    rental?.vehicle?.vehicle_model?.hourly_price ??
    0
  );
  if (directVehicleHourlyRate > 0) return directVehicleHourlyRate;

  const storedUnitPrice = Number(rental?.unit_price || 0);
  if (String(rental?.rental_type || '').toLowerCase() === 'hourly' && storedUnitPrice > 0) {
    return storedUnitPrice;
  }

  const quantityHours = Number(rental?.quantity_hours || 0);
  const storedTotalAmount = Number(rental?.total_amount || 0);
  if (storedTotalAmount > 0 && quantityHours > 0) {
    return storedTotalAmount / quantityHours;
  }

  return 0;
};

const getRentalEffectiveEndTime = (rental = {}) =>
  rental?.actual_return_time ||
  rental?.actual_end_time ||
  (
    (
      String(rental?.rental_status || '').toLowerCase() === 'completed' ||
      Boolean(rental?.completed_at)
    )
      ? (
          rental?.completed_at ||
          rental?.rental_completed_at ||
          rental?.actual_end_date
        )
      : null
  ) ||
  rental?.rental_end_date ||
  null;

const getRentalDisplayEndTime = (rental = {}) => {
  const actualReturnValue =
    rental?.actual_return_time ||
    rental?.actual_end_time ||
    null;
  if (actualReturnValue) return actualReturnValue;

  const completedAtValue =
    String(rental?.rental_status || '').toLowerCase() === 'completed' || rental?.completed_at
      ? (rental?.completed_at || rental?.rental_completed_at || null)
      : null;
  if (completedAtValue) return completedAtValue;

  const actualEndValue =
    String(rental?.rental_status || '').toLowerCase() === 'completed' || rental?.completed_at
      ? (rental?.actual_end_date || null)
      : null;
  const scheduledEndValue = rental?.rental_end_date || null;

  return actualEndValue || scheduledEndValue || null;
};

const getPackageTotalIncludedKilometers = (rental = {}, pkg = null) => {
  const resolvedPackage = pkg || getRentalKilometerPackage(rental);
  if (!resolvedPackage) return 0;

  const expectedIncludedKm = getPackageExpectedTotalIncludedKilometers(rental, resolvedPackage);
  if (expectedIncludedKm > 0) return expectedIncludedKm;

  const storedBookedLimit = getStoredBookedPackageTotalIncludedKilometers(rental, resolvedPackage);
  if (storedBookedLimit > 0) return storedBookedLimit;

  return Number.parseFloat(rental?.included_kilometers_applied || 0) || 0;
};

const getConfiguredPackageTotalIncludedKilometers = (rental = {}, pkg = null) => {
  const resolvedPackage = pkg || getRentalKilometerPackage(rental);
  if (!resolvedPackage) return 0;
  if (isUnlimitedKilometerPackage(resolvedPackage)) return Number.POSITIVE_INFINITY;

  const expectedIncludedKm = getPackageExpectedTotalIncludedKilometers(rental, resolvedPackage);
  if (expectedIncludedKm > 0) return expectedIncludedKm;

  const storedTotalIncludedKm = getStoredBookedPackageTotalIncludedKilometers(rental, resolvedPackage);
  if (storedTotalIncludedKm > 0) return storedTotalIncludedKm;

  return Number.parseFloat(rental?.included_kilometers_applied || 0) || 0;
};

const getKilometerPackageName = (pkg = null, fallback = '') =>
  pkg?.name ||
  pkg?.package_name ||
  pkg?.display_name ||
  pkg?.displayName ||
  fallback;

const isUnlimitedKilometerPackage = (pkg = null) => {
  if (!pkg) return false;

  const rawLimitValue =
    pkg?.included_kilometers ??
    pkg?.includedKilometers ??
    pkg?.included_km ??
    pkg?.includedKm;
  const rawLimit = Number.parseFloat(
    rawLimitValue ??
    0
  );
  const name = String(getKilometerPackageName(pkg) || '').toLowerCase();
  const kind = String(pkg?.kind || pkg?.package_type || pkg?.type || '').toLowerCase();
  const hasNoFiniteLimit =
    rawLimitValue === null ||
    rawLimitValue === undefined ||
    rawLimitValue === '' ||
    (Number.isFinite(rawLimit) && rawLimit <= 0);

  return (
    name.includes('unlimited') ||
    name.includes('unlimted') ||
    name.includes('illimité') ||
    kind.includes('unlimited') ||
    (hasNoFiniteLimit && (name.includes('km') || name.includes('kilometer')))
  );
};

const dedupeKilometerPackages = (packages = []) => {
  const seen = new Set();

  return (Array.isArray(packages) ? packages : [])
    .filter(Boolean)
    .filter((pkg) => {
      const key = String(pkg?.id || `${getKilometerPackageName(pkg)}-${pkg?.fixed_amount}-${pkg?.included_kilometers}`);
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
};

const getKilometerPackageDurationUnits = (pkg = null) => {
  const name = String(getKilometerPackageName(pkg) || '').toLowerCase();
  if (name.includes('30 min') || name.includes('30-minute')) return 0.5;
  const hourMatch = name.match(/(\d+(?:\.\d+)?)\s*(?:h|hour|hours)\b/);
  if (hourMatch) return Number(hourMatch[1]);

  const directDuration = Number(
    pkg?.duration_units ??
    pkg?.duration ??
    pkg?.package_duration_units ??
    pkg?.durationUnits
  );
  if (Number.isFinite(directDuration) && directDuration > 0) return directDuration;

  return null;
};

const isKilometerPackageCompatibleWithRentalDuration = (rental = {}, pkg = null, originalPackage = null) => {
  if (!pkg) return false;
  if (originalPackage?.id && pkg?.id && String(originalPackage.id) === String(pkg.id)) return true;

  const rentalType = String(rental?.rental_type || '').toLowerCase();
  const packageName = String(getKilometerPackageName(pkg) || '').toLowerCase();
  const rateTypeId = Number(pkg?.rate_type_id ?? pkg?.rateTypeId ?? 0) || 0;
  const rateTypeName = String(pkg?.rate_types?.name ?? pkg?.rate_type?.name ?? pkg?.rate_type_name ?? '').toLowerCase();
  if (rentalType === 'hourly' && (packageName.includes('per day') || packageName.includes('daily') || packageName.includes('day'))) {
    return false;
  }
  if (rentalType === 'daily' && (packageName.includes('per hour') || packageName.includes('hourly'))) {
    return false;
  }

  if (rentalType === 'hourly' && rateTypeId && rateTypeId !== 1) return false;
  if (rentalType === 'daily' && rateTypeId && rateTypeId !== 2) return false;
  if (rentalType === 'hourly' && rateTypeName.includes('day')) return false;
  if (rentalType === 'daily' && rateTypeName.includes('hour')) return false;

  const rentalDuration = getRentalActualDurationUnits(rental) || getRentalDurationUnits(rental) || 1;
  const packageDuration = getKilometerPackageDurationUnits(pkg);
  const tolerance = 0.01;
  if (!Number.isFinite(packageDuration) || packageDuration <= 0) return false;

  if (rentalType === 'hourly') {
    if (Math.abs(packageDuration - 1) <= tolerance) return true;
    return Math.abs(packageDuration - rentalDuration) <= tolerance;
  }

  if (rentalType === 'daily') {
    if (Math.abs(packageDuration - 1) <= tolerance) return true;
    return Math.abs(packageDuration - rentalDuration) <= tolerance;
  }

  return true;
};

const getPackageBaseIncludedKilometers = (pkg = null) => {
  if (isUnlimitedKilometerPackage(pkg)) return Number.POSITIVE_INFINITY;
  return Number(
    pkg?.included_kilometers ??
    pkg?.includedKilometers ??
    pkg?.included_km ??
    pkg?.includedKm ??
    0
  ) || 0;
};

const selectAppliedKilometerPackage = ({
  rental = {},
  bookedPackage = null,
  packageDetails = null,
  availablePackages = [],
  gracePeriodMinutes = DEFAULT_RENTAL_TIMING_SETTINGS.graceMinutes,
  totalDistance = 0,
  allowAutoUpgrade = true,
} = {}) => {
  if (!isPackagePricingEnabled(rental)) {
    return {
      originalPackage: null,
      appliedPackage: null,
      originalLimit: 0,
      appliedLimit: 0,
      originalPrice: 0,
      appliedPrice: 0,
      appliedExtraRate: 0,
      upgraded: false,
      overageKm: 0,
      overageCharge: 0,
    };
  }

  const originalPackage = bookedPackage || getRentalKilometerPackage(rental, packageDetails);
  const safeDistance = Math.max(0, Number(totalDistance || 0) || 0);
  const originalPrice = originalPackage
    ? Math.max(0, Number(getBookedPackageSnapshotTotal(rental, originalPackage) || 0) || 0)
    : 0;

  if (originalPackage && isUnlimitedKilometerPackage(originalPackage)) {
    return {
      originalPackage,
      appliedPackage: originalPackage,
      originalLimit: Number.POSITIVE_INFINITY,
      appliedLimit: Number.POSITIVE_INFINITY,
      originalPrice,
      appliedPrice: originalPrice,
      appliedExtraRate: 0,
      upgraded: false,
      overageKm: 0,
      overageCharge: 0,
      totalDistance: safeDistance,
    };
  }

  const candidatePackages = dedupeKilometerPackages([
    ...availablePackages,
    originalPackage,
    rental?.package,
    packageDetails,
  ]);

  const rentalDurationUnits = getRentalActualDurationUnits(rental) || getRentalDurationUnits(rental) || 1;
  const simplePricingSummary = calculateSimpleRentalPricing({
    startTime: rental?.started_at || rental?.rental_start_date,
    endTime: getRentalEffectiveEndTime(rental),
    gracePeriodMinutes,
    hourlyRate: getRentalHourlyRate(rental),
    totalKmUsed: safeDistance,
    packages: candidatePackages,
    rentalType: rental?.rental_type,
    originalPackage,
    durationUnits: rentalDurationUnits,
  });
  const selectedBySharedPricing = simplePricingSummary?.selectedPackage || null;
  const selectedPackageId = selectedBySharedPricing?.id ? String(selectedBySharedPricing.id) : null;
  const options = candidatePackages
    .filter((pkg) => isKilometerPackageCompatibleWithRentalDuration(rental, pkg, originalPackage))
    .map((pkg) => {
      const unlimited = isUnlimitedKilometerPackage(pkg);
      const includedKm = unlimited ? Number.POSITIVE_INFINITY : Number(getConfiguredPackageTotalIncludedKilometers(rental, pkg) || 0);
      const isOriginalPackage =
        Boolean(originalPackage?.id && pkg?.id) &&
        String(originalPackage.id) === String(pkg.id);

      return {
        pkg,
        includedKm,
        totalPrice: isOriginalPackage
          ? Math.max(0, Number(getBookedPackageSnapshotTotal(rental, pkg) || 0) || 0)
          : Math.max(0, Number(getPackageContractBaseTotal(rental, pkg, { preferPackageAmount: true }) || 0) || 0),
        unlimited,
      };
    })
    .filter((option) => option.unlimited || option.includedKm > 0);

  const originalLimit = originalPackage
    ? Number(getConfiguredPackageTotalIncludedKilometers(rental, originalPackage) || 0)
    : 0;
  if (!allowAutoUpgrade) {
    const appliedPackage = originalPackage || null;
    const appliedLimit = Number.isFinite(originalLimit) ? originalLimit : 0;
    const appliedPrice = Number.isFinite(originalPrice) ? originalPrice : 0;
    const appliedExtraRate = Number.parseFloat(appliedPackage?.extra_km_rate || rental?.extra_km_rate_applied || 0) || 0;
    const overageKm = Number.isFinite(appliedLimit) ? Math.max(0, safeDistance - appliedLimit) : 0;
    const overageCharge = overageKm * appliedExtraRate;

    return {
      originalPackage,
      appliedPackage,
      originalLimit,
      appliedLimit,
      originalPrice,
      appliedPrice,
      appliedExtraRate,
      upgraded: false,
      overageKm,
      overageCharge,
      totalDistance: safeDistance,
    };
  }
  const appliedOption = (
    selectedPackageId
      ? options.find((option) => String(option.pkg?.id || '') === selectedPackageId)
      : null
  ) || options.find((option) => option.pkg?.id && originalPackage?.id && String(option.pkg.id) === String(originalPackage.id)) || options[0] || null;
  const shouldKeepBookedPackage =
    originalPackage &&
    originalPrice > 0 &&
    (
      !appliedOption ||
      (Number(appliedOption?.totalPrice || 0) || 0) < originalPrice
    );
  const appliedPackage = shouldKeepBookedPackage
    ? originalPackage
    : (appliedOption?.pkg || originalPackage || null);
  const appliedLimit = shouldKeepBookedPackage
    ? originalLimit
    : Number(simplePricingSummary?.packageLimitKm || appliedOption?.includedKm || originalLimit || 0);
  const appliedPrice = shouldKeepBookedPackage
    ? originalPrice
    : Math.max(Number(appliedOption?.totalPrice || 0) || 0, originalPrice);
  const appliedExtraRate = Number.parseFloat(appliedPackage?.extra_km_rate || rental?.extra_km_rate_applied || 0) || 0;
  const upgraded = Boolean(
    originalPackage?.id &&
    appliedPackage?.id &&
    String(originalPackage.id) !== String(appliedPackage.id) &&
    appliedPrice > originalPrice
  );
  const overageKm = Number(simplePricingSummary?.packageOverflowKm ?? (Number.isFinite(appliedLimit) ? Math.max(0, safeDistance - appliedLimit) : 0));
  const overageCharge = overageKm * appliedExtraRate;

  return {
    originalPackage,
    appliedPackage,
    originalLimit,
    appliedLimit,
    originalPrice,
    appliedPrice,
    appliedExtraRate,
    upgraded,
    overageKm,
    overageCharge,
    totalDistance: safeDistance,
  };
};

const getDisplayRentalDurationUnits = (rental = {}) => {
  if (String(rental?.rental_type || '').toLowerCase() !== 'hourly') {
    return Number(getRentalDurationUnits(rental));
  }

  const actualDuration = getRentalActualDurationUnits(rental);
  if (actualDuration) return actualDuration;

  const startValue = rental?.started_at || rental?.rental_start_date;
  const endValue = getRentalDisplayEndTime(rental);

  if (startValue && endValue) {
    const start = new Date(startValue);
    const end = new Date(endValue);
    const diffMs = end.getTime() - start.getTime();

    if (Number.isFinite(diffMs) && diffMs > 0) {
      const rawHours = diffMs / (1000 * 60 * 60);
      const roundedHalfHours = Math.round(rawHours * 2) / 2;
      if (roundedHalfHours > 0) {
        return roundedHalfHours;
      }
    }
  }

  return Number(getRentalDurationUnits(rental));
};

const getCompletedHourlyElapsedMinutes = (rental = {}) => {
  if (String(rental?.rental_type || '').toLowerCase() !== 'hourly') return null;
  const isCompletedRental =
    String(rental?.rental_status || '').toLowerCase() === 'completed' ||
    Boolean(rental?.completed_at);
  if (!isCompletedRental) return null;

  const startValue = rental?.started_at || rental?.rental_start_date;
  const endValue = getRentalDisplayEndTime(rental) || getRentalEffectiveEndTime(rental);
  const start = new Date(startValue || '');
  const end = new Date(endValue || '');
  const diffMs = end.getTime() - start.getTime();

  if (!Number.isFinite(start.getTime()) || !Number.isFinite(end.getTime()) || !Number.isFinite(diffMs) || diffMs <= 0) {
    return null;
  }

  return Math.max(1, Math.round(diffMs / 60000));
};

const formatExactHourlyDurationLabel = (minutes, isFrench = false) => {
  const safeMinutes = Math.max(0, Math.round(Number(minutes || 0) || 0));
  const trLocal = (en, fr) => (isFrench ? fr : en);
  if (safeMinutes <= 0) return trLocal('0 min', '0 min');
  if (safeMinutes < 60) return trLocal(`${safeMinutes} min`, `${safeMinutes} min`);

  const hours = Math.floor(safeMinutes / 60);
  const remainingMinutes = safeMinutes % 60;

  if (remainingMinutes <= 0) {
    return trLocal(
      `${hours} hour${hours > 1 ? 's' : ''}`,
      `${hours} heure${hours > 1 ? 's' : ''}`
    );
  }

  return trLocal(
    `${hours}h ${remainingMinutes}m`,
    `${hours} h ${remainingMinutes} min`
  );
};

const formatRentalDurationLabel = (rental = {}, isFrench = false) => {
  const duration = getDisplayRentalDurationUnits(rental);
  const trLocal = (en, fr) => (isFrench ? fr : en);

  if (String(rental?.rental_type || '').toLowerCase() === 'hourly') {
    const completedElapsedMinutes = getCompletedHourlyElapsedMinutes(rental);
    if (completedElapsedMinutes) {
      return formatExactHourlyDurationLabel(completedElapsedMinutes, isFrench);
    }
    if (duration === 0.5) return trLocal('30 min', '30 min');
    if (duration === 1) return trLocal('1 hour', '1 heure');
    if (duration === 1.5) return trLocal('1.5 hours', '1,5 heure');
    return trLocal(`${duration} hours`, `${duration} heures`);
  }

  if (duration === 1) {
    return trLocal('1 day', '1 jour');
  }

  return trLocal(`${duration} days`, `${duration} jours`);
};

const isFlatHourlyTierRental = (rental = {}, packageDetails = null) =>
  !getRentalKilometerPackage(rental, packageDetails) &&
  String(rental?.rental_type || '').toLowerCase() === 'hourly' &&
  Number(getDisplayRentalDurationUnits(rental)) === 1.5;

const getRentalDetailsSnapshotKey = (rentalId) => `rental_details_snapshot_${String(rentalId || '').trim()}`;

const readRentalDetailsSnapshot = (rentalId) => {
  if (typeof window === 'undefined' || !rentalId) return null;

  try {
    const raw = window.sessionStorage.getItem(getRentalDetailsSnapshotKey(rentalId));
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch (error) {
    console.warn('Unable to read rental details snapshot:', error);
    return null;
  }
};

const writeRentalDetailsSnapshot = (rentalId, snapshot) => {
  if (typeof window === 'undefined' || !rentalId || !snapshot || typeof snapshot !== 'object') return;

  try {
    window.sessionStorage.setItem(
      getRentalDetailsSnapshotKey(rentalId),
      JSON.stringify({
        ...snapshot,
        __cachedAt: new Date().toISOString(),
      })
    );
  } catch (error) {
    console.warn('Unable to write rental details snapshot:', error);
  }
};

const hasRecordedReturnFuel = (rental, endFuelLevel) => {
  return endFuelLevel !== null && endFuelLevel !== undefined ||
    rental?.end_fuel_level !== null && rental?.end_fuel_level !== undefined ||
    String(rental?.rental_status || '').toLowerCase() === 'completed';
};

const getEffectiveFuelChargeAmount = ({ rental, endFuelLevel, fuelCharge, fuelChargeEnabled }) => {
  if (!fuelChargeEnabled || !hasRecordedReturnFuel(rental, endFuelLevel)) {
    return 0;
  }

  return parseFloat(fuelCharge || rental?.fuel_charge || 0) || 0;
};

const getCorrectedDisplayedPaidAmount = ({ rental, endFuelLevel, fuelCharge, fuelChargeEnabled }) => {
  const rawPaidAmount = parseFloat(rental?.deposit_amount || 0) || 0;
  if (fuelChargeEnabled === false || rental?.fuel_charge_enabled === false) {
    return rawPaidAmount;
  }
  const effectiveFuelCharge = getEffectiveFuelChargeAmount({ rental, endFuelLevel, fuelCharge, fuelChargeEnabled });
  const rawFuelCharge = parseFloat(rental?.fuel_charge || 0) || 0;
  const staleFuelCharge = Math.max(0, rawFuelCharge - effectiveFuelCharge);
  const rawTotalAmount = parseFloat(rental?.total_amount || 0) || 0;
  const paymentStatus = normalizePaymentStatus(rental?.payment_status, rental?.remaining_amount);
  const mirrorsStoredTotal = rawPaidAmount > 0 && rawTotalAmount > 0 && Math.abs(rawPaidAmount - rawTotalAmount) < 0.01;
  const shouldNormalizePaidAmount = staleFuelCharge > 0 && mirrorsStoredTotal && paymentStatus === 'paid';

  return shouldNormalizePaidAmount
    ? Math.max(0, rawPaidAmount - staleFuelCharge)
    : rawPaidAmount;
};

const getLateFeeAmount = (rental = {}) => (
  Math.max(0, Number(rental?.late_fee_amount ?? rental?.late_fee ?? 0) || 0)
);

const sortExtensionHistoryEntries = (entries = []) => (
  [...(Array.isArray(entries) ? entries : [])].sort((a, b) => {
    const aTime = new Date(a?.requested_at || a?.created_at || a?.updated_at || 0).getTime();
    const bTime = new Date(b?.requested_at || b?.created_at || b?.updated_at || 0).getTime();
    return bTime - aTime;
  })
);

const calculateHourlyLateReturnFeePreview = ({
  rental = {},
  completedAt = null,
  thresholdMinutes = DEFAULT_RENTAL_TIMING_SETTINGS.extraHourThresholdMinutes,
  hourlyRate = 0,
  currentLateFeeAmount = getLateFeeAmount(rental),
} = {}) => {
  if (!rental?.id) return null;
  if (String(rental?.rental_type || '').toLowerCase() !== 'hourly') return null;
  if (isPackagePricingEnabled(rental)) return null;

  const startTime = new Date(rental?.started_at || rental?.rental_start_date || '');
  const closeTime = new Date(
    completedAt ||
    rental?.actual_end_date ||
    rental?.actual_return_time ||
    rental?.actual_end_time ||
    rental?.rental_end_date ||
    ''
  );
  if (!Number.isFinite(startTime.getTime()) || !Number.isFinite(closeTime.getTime())) return null;

  const safeThresholdMinutes = Math.max(
    0,
    Number(thresholdMinutes) || DEFAULT_RENTAL_TIMING_SETTINGS.extraHourThresholdMinutes
  );
  const safeHourlyRate = Math.max(0, Number(hourlyRate || 0) || 0);
  if (safeHourlyRate <= 0) return null;

  const includedHours = Math.max(
    1,
    Math.ceil(
      Number(rental?.quantity_hours || 0) ||
      Number(getRentalDurationUnits(rental) || 0) ||
      1
    )
  );
  const durationMinutes = Math.max(0, Math.ceil((closeTime.getTime() - startTime.getTime()) / 60000));
  const includedMinutes = includedHours * 60;
  const minutesPastGrace = Math.max(0, durationMinutes - includedMinutes - safeThresholdMinutes);
  const billableLateHours = minutesPastGrace > 0 ? Math.max(1, Math.ceil(minutesPastGrace / 60)) : 0;
  const expectedLateFeeAmount = Number((billableLateHours * safeHourlyRate).toFixed(2));

  return {
    durationMinutes,
    includedHours,
    includedMinutes,
    thresholdMinutes: safeThresholdMinutes,
    minutesPastGrace,
    billableLateHours,
    hourlyRate: safeHourlyRate,
    expectedLateFeeAmount,
    appliedLateFeeAmount: Math.max(0, Number(currentLateFeeAmount || 0) || 0),
    isLateAfterGrace: minutesPastGrace > 0,
  };
};

