  // Handle price approval WhatsApp notification (manual trigger)
  const handlePriceApprovalRequest = async () => {
    if (!rental?.id) {
      toast.error("Rental information not available.");
      return;
    }

    setIsSharing(true);
    
    try {
      const allUsers = await getUsers();
      const admins = (allUsers || []).filter(
        (user) =>
          ['admin', 'owner'].includes(String(user.role || '')) &&
          user.whatsapp_notifications
      );
      
      if (!admins || admins.length === 0) {
        toast.error("No admins have WhatsApp notifications enabled.");
        setIsSharing(false);
        return;
      }
      
      const rentalDetailsUrl = `${window.location.origin}/admin/rentals/${rental.id}`;
      
      const message = `🔔 Price Override Request\n\nRental ID: ${rental.rental_id}\nCustomer: ${rental.customer_name}\nVehicle: ${rental.vehicle?.name} - ${rental.vehicle?.model}\n\n💰 Price Details:\n• Current Price: ${rental.total_amount} MAD\n• Requested Price: ${rental.pending_total_request} MAD\n• Reason: ${rental.price_override_reason || 'No reason provided'}\n\n🔗 Review & Approve:\n${rentalDetailsUrl}\n\nClick the link above to review and approve the price change.`;
      
      let sentCount = 0;
      for (const admin of admins) {
        if (admin.phone_number) {
          const whatsappUrl = buildWhatsAppSendUrl(admin.phone_number, message);
          window.open(whatsappUrl, '_blank');
          sentCount++;
          await new Promise(resolve => setTimeout(resolve, 100));
        }
      }
      
      if (sentCount > 0) {
        toast.success(`Price change request sent to ${sentCount} admin(s).`);
      } else {
        toast.error("No admins have valid phone numbers configured.");
      }
      
    } catch (error) {
      console.error('❌ Error sending price approval:', error);
      toast.error(`Failed to send approval request: ${error.message}`);
    } finally {
      setIsSharing(false);
    }
  };

  const getShortenedGeneratedDocumentUrl = async (documentType) => {
    const isContract = documentType === 'contract';
    const currentShortUrl = isContract ? shortContractUrlRef.current : shortReceiptUrlRef.current;
    const currentPublicUrl = isContract ? contractUrlRef.current : receiptUrlRef.current;
    const shouldReuseExistingUrl = isContract;

    if (shouldReuseExistingUrl && currentShortUrl && currentPublicUrl) {
      return currentShortUrl;
    }

    const uploadedPublicUrl = (shouldReuseExistingUrl ? currentPublicUrl : null) || (
      isContract
        ? await handlePrintContract({ shareOnly: true })
        : await handlePrintReceipt({ shareOnly: true })
    );

    if (!uploadedPublicUrl) {
      return null;
    }

    const shortened = await shortenUrl(uploadedPublicUrl, documentType);
    if (isContract) {
      contractUrlRef.current = uploadedPublicUrl;
      shortContractUrlRef.current = shortened;
    } else {
      receiptUrlRef.current = uploadedPublicUrl;
      shortReceiptUrlRef.current = shortened;
    }
    return shortened;
  };

  const getGeneratedDocumentPublicUrl = async (documentType) => {
    const isContract = documentType === 'contract';
    const currentPublicUrl = isContract ? contractUrlRef.current : receiptUrlRef.current;
    const shouldReuseExistingUrl = isContract;

    if (shouldReuseExistingUrl && currentPublicUrl) {
      return currentPublicUrl;
    }

    const uploadedPublicUrl = (shouldReuseExistingUrl ? currentPublicUrl : null) || (
      isContract
        ? await handlePrintContract({ shareOnly: true })
        : await handlePrintReceipt({ shareOnly: true })
    );

    if (!uploadedPublicUrl) {
      return null;
    }

    if (isContract) {
      contractUrlRef.current = uploadedPublicUrl;
      shortContractUrlRef.current = null;
    } else {
      receiptUrlRef.current = uploadedPublicUrl;
      shortReceiptUrlRef.current = null;
    }

    return uploadedPublicUrl;
  };

  const createDocumentShareRecord = async ({ shareType, payload, documentType = 'other' }) => {
    const { data: sessionData } = await supabase.auth.getSession();
    const accessToken = sessionData?.session?.access_token;
    const encodedPayload = await encodePublicSharePayload(payload);

    const response = await fetch('/api/public-links?resource=document-shares&action=create', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
        ...(accessToken ? { Authorization: `Bearer ${accessToken}` } : {}),
      },
      body: JSON.stringify({
        shareType,
        rentalId: rental?.id || null,
        ...(encodedPayload ? { payloadEncoded: encodedPayload } : { payload }),
      }),
    });

    const body = await response.json().catch(() => ({}));
    if (!response.ok || !body?.url) {
      const responseError = body?.error;
      const errorMessage =
        typeof responseError === 'string'
          ? responseError
          : responseError?.message || responseError?.error || (
              responseError ? JSON.stringify(responseError) : 'Failed to create public share'
            );
      throw new Error(errorMessage);
    }

    return body.url;
  };

  const createShortDocumentShareRecord = async ({ shareType, payload, documentType = 'other' }) => {
    const publicUrl = await createDocumentShareRecord({ shareType, payload, documentType });
    if (!publicUrl) return null;
    // Document-share records already return compact /d/:token links. Sending them
    // back through short-links can turn a valid share into a 413 failure.
    return publicUrl;
  };


