  // Update fuel charge toggle
const handleFuelChargeToggle = async (enabled) => {
  try {
    setFuelChargeEnabled(enabled);
    
    // If disabling fuel charge, set fuel_charge to 0 in the database
    // If enabling, recalculate based on current fuel levels
    let newFuelCharge = 0;
    
    if (enabled) {
      const startLevel = startFuelLevel ?? rental?.start_fuel_level;
      const endLevel = endFuelLevel ?? rental?.end_fuel_level;
      
      if (startLevel !== null && endLevel !== null && endLevel < startLevel) {
        newFuelCharge = FuelPricingService.calculateFuelCharge(
          startLevel,
          endLevel,
          fuelPricePerLine,
          rental?.rental_type || 'daily'
        );
      }
    }

    const currentFuelChargeAmount = Math.max(0, Number(rentalBillingSummary?.fuelChargeAmount || 0) || 0);
    const currentGrandTotal = Math.max(0, Number(rentalBillingSummary?.grandTotal || 0) || 0);
    const nextGrandTotal = Math.max(0, currentGrandTotal - currentFuelChargeAmount + newFuelCharge);
    const amountDueState = buildAmountDueStateForGrandTotalChange({
      rentalLike: rental,
      amountDueMeta: amountDueAuditMeta || getInlineAmountDueOverrideMeta(rental),
      currentGrandTotal,
      nextGrandTotal,
    });
    
    const { data: updatedRental, error } = await updateRentalWithSchemaFallback({
      fuel_charge_enabled: enabled,
      fuel_charge: newFuelCharge,
      remaining_amount: amountDueState.nextRemainingAmount,
      payment_status: amountDueState.nextPaymentStatus,
      updated_at: new Date().toISOString(),
    });

    if (error) throw error;
    
    setFuelCharge(newFuelCharge);
    setRental(updatedRental);
    toast.success(`Fuel charge ${enabled ? 'enabled' : 'disabled'}`);
    
  } catch (err) {
    console.error('Error updating fuel charge:', err);
    toast.error('Failed to update fuel charge');
    // Revert state on error
    setFuelChargeEnabled(!enabled);
  }
};

  const persistVehicleReport = async () => {
    if (!vehicleReportDraft.enabled) {
      return null;
    }

    if (!rental?.vehicle_id) {
      throw new Error('Vehicle information is missing for this rental');
    }

    if (!hasClosingInspectionMedia) {
      throw new Error('Upload closing photos or videos before saving the report');
    }

    if (reportNeedsAffectedAreas && !hasAffectedAreas) {
      throw new Error('Please tap the vehicle map to mark the affected area');
    }

    setSavingVehicleReport(true);
    try {
      const actorName = currentUser?.full_name || currentUser?.email || 'Staff';
      const reportPayload = {
        rental_id: rental.id,
        vehicle_id: rental.vehicle_id,
        report_type: vehicleReportDraft.report_type,
        severity: vehicleReportDraft.severity,
        description: vehicleReportDraft.description.trim(),
        affected_areas: Array.isArray(vehicleReportDraft.affected_areas)
          ? vehicleReportDraft.affected_areas
          : [],
        photos: closingMedia.map((media) => ({
          id: media.id,
          url: media.url || media.public_url || media.video_url,
          type: media.file_type || (media.isImage ? 'image/*' : 'video/*'),
          phase: media.phase || 'in',
          created_at: media.created_at || new Date().toISOString(),
        })),
        customer_chargeable: vehicleReportDraft.customer_chargeable,
        customer_charge_amount: vehicleReportDraft.send_to_maintenance ? 0 : (vehicleReportDraft.customer_charge_amount || 0),
        send_to_maintenance: vehicleReportDraft.send_to_maintenance,
        created_by_user_id: currentUser?.id || null,
        created_by_name: actorName,
      };

      let nextReport = vehicleReport
        ? await VehicleReportService.updateReport(vehicleReport.id, reportPayload)
        : await VehicleReportService.createReport(reportPayload);

      if (reportPayload.send_to_maintenance && !nextReport.maintenance_id) {
        const maintenance = await VehicleReportService.createMaintenanceFromReport({
          report: nextReport,
          rental,
          actorName,
        });

        if (maintenance) {
          nextReport = await VehicleReportService.updateReport(nextReport.id, {
            maintenance_id: maintenance.id,
            maintenance_cost_total: maintenance.cost || 0,
            status: 'maintenance_created',
          });

          await supabase
            .from('saharax_0u4w4d_vehicles')
            .update({
              status: 'maintenance',
              updated_at: new Date().toISOString(),
            })
            .eq('id', rental.vehicle_id);
        }
      }

      const hydratedReport = await VehicleReportService.hydrateReportWithMaintenance(nextReport, { rental });
      setRequiresClosingInspectionReview(false);
      setVehicleReport(hydratedReport);
      setRental(prev => prev ? ({ ...prev, vehicleReport: hydratedReport }) : prev);
      setFinishRentalSteps(prev => ({
        ...prev,
        closingVideoComplete: true,
      }));
      await broadcastRentalWorkflowUpdate('finish', 'closing_inspection', {
        showWorkflow: true,
        steps: {
          ...buildFinishWorkflowState(),
          closingVideoComplete: true,
        },
      });
      toast.success(reportPayload.send_to_maintenance ? 'Vehicle report saved and maintenance created' : 'Vehicle report saved');
      return hydratedReport;
    } finally {
      setSavingVehicleReport(false);
    }
  };

  const toggleAffectedArea = (areaId) => {
    setVehicleReportDraft(prev => {
      const currentAreas = Array.isArray(prev.affected_areas) ? prev.affected_areas : [];
      const nextAreas = currentAreas.includes(areaId)
        ? currentAreas.filter((item) => item !== areaId)
        : [...currentAreas, areaId];

      return {
        ...prev,
        affected_areas: nextAreas,
      };
    });
  };

  const clearFinishWorkflowState = () => {
    if (!finishWorkflowStorageKey || typeof window === 'undefined') return;
    removeStorageValues(window.localStorage, finishWorkflowStorageKeys);
  };

  const persistFinishWorkflowState = (nextDraft = vehicleReportDraft, extras = {}) => {
    if (!finishWorkflowStorageKey || typeof window === 'undefined') return;
    window.localStorage.setItem(
      finishWorkflowStorageKey,
      JSON.stringify({
        showWorkflow: true,
        resolutionMode: extras.resolutionMode || finishResolutionMode,
        vehicleReportDraft: nextDraft,
        returnStartedAt: extras.returnStartedAt || returnWorkflowBillingResult?.calculatedAt || null,
        billingResult: extras.billingResult || returnWorkflowBillingResult || null,
        updatedAt: new Date().toISOString(),
      })
    );
  };

  const buildFinishWorkflowState = () => ({
    showWorkflow: true,
    closingVideoComplete: closingInspectionStepComplete,
    closingDocumentComplete: true,
    endOdometerComplete: !!rental?.ending_odometer,
    endEngineHoursComplete: rental?.end_engine_hours !== null && rental?.end_engine_hours !== undefined,
    endFuelComplete: endFuelLevel !== null || rental?.end_fuel_level !== null,
  });

  const openFinishWorkflow = async (resolutionMode = finishResolutionMode) => {
    if (isImpounded) {
      toast.error(tr(
        'This rental is on an unresolved towing hold. Release the hold before finishing the rental.',
        'Cette location est sous un maintien de fourrière non résolu. Libérez la retenue avant de terminer la location.'
      ));
      return;
    }

    const returnStartedAt = new Date().toISOString();
    let workflowRental = rental;
    let autoVoidResult = null;
    let overtimeAdjustment = null;

    try {
      autoVoidResult = await maybeAutoVoidLatestExtensionOnReturn({
        completedAt: returnStartedAt,
        currentRental: workflowRental,
      });
      workflowRental = autoVoidResult?.rental || workflowRental;

      const overtimeResult = await applyBaseHourlyOvertimeOnClose({
        completedAt: returnStartedAt,
        currentRental: workflowRental,
      });
      workflowRental = overtimeResult?.rental || workflowRental;
      overtimeAdjustment = overtimeResult?.adjustment || null;
    } catch (error) {
      console.error('❌ Failed to update return billing before finish workflow:', error);
      toast.error(tr(
        'Could not update return billing. Please try End Now again before closing.',
        'Impossible de mettre à jour la facturation du retour. Réessayez Terminer maintenant avant la clôture.'
      ));
      return;
    }

    const billingResult = overtimeAdjustment || autoVoidResult?.autoVoided
      ? {
          calculatedAt: returnStartedAt,
          autoVoidedExtension: Boolean(autoVoidResult?.autoVoided),
          overtimeAdjustment,
        }
      : null;
    setReturnWorkflowBillingResult(billingResult);

    const nextState = buildFinishWorkflowState();
    setFinishRentalSteps(nextState);
    persistFinishWorkflowState(vehicleReportDraft, {
      returnStartedAt,
      billingResult,
      resolutionMode,
    });
    await broadcastRentalWorkflowUpdate('finish', 'workflow_opened', {
      showWorkflow: true,
      steps: nextState,
      return_billing_updated: Boolean(billingResult),
      rental_end_date: workflowRental?.rental_end_date,
      actual_end_date: workflowRental?.actual_end_date,
      quantity_hours: workflowRental?.quantity_hours,
      total_amount: workflowRental?.total_amount,
      remaining_amount: workflowRental?.remaining_amount,
    });
  };

  const handleCancelFinishWorkflow = async () => {
    try {
      if (rental?.id && rental?.rental_status !== 'completed') {
        const { error } = await supabase
          .from('app_4c3a7a6153_rentals')
          .update({
            ending_odometer: null,
            end_engine_hours: null,
            end_fuel_level: null,
            fuel_charge: 0,
            updated_at: new Date().toISOString(),
          })
          .eq('id', rental.id);

        if (error) throw error;

        setRental((prev) => prev ? ({
          ...prev,
          ending_odometer: null,
          end_engine_hours: null,
          end_fuel_level: null,
          fuel_charge: 0,
        }) : prev);
      }

      setEndOdometer('');
      setEndOdometerEditValue('');
      setIsEditingEndOdometer(false);
      setShowEndOdometerPrompt(false);
      setEndEngineHours('');
      setEndEngineHoursEditValue('');
      setIsEditingEndEngineHours(false);
      setShowEndEngineHoursPrompt(false);
      setEndFuelLevel(null);
      setFuelCharge(0);
      setShowEndFuelModal(false);
      setRequiresClosingInspectionReview(closingMedia.length > 0);
      setReturnWorkflowBillingResult(null);
      setFinishResolutionMode('standard');
      setShowVehicleIssueResolutionModal(false);

      const nextState = {
        showWorkflow: false,
        closingVideoComplete: false,
        closingDocumentComplete: true,
        endOdometerComplete: false,
        endEngineHoursComplete: false,
        endFuelComplete: false
      };
      setFinishRentalSteps(nextState);
      clearFinishWorkflowState();
      setFinishWorkflowTakeover(false);
      await broadcastRentalWorkflowUpdate('finish', 'workflow_closed', {
        showWorkflow: false,
        steps: nextState,
        ending_odometer: null,
        end_engine_hours: null,
        end_fuel_level: null,
        fuel_charge: 0,
      });
    } catch (err) {
      console.error('❌ Error cancelling finish workflow:', err);
      toast.error(tr('Failed to cancel finish workflow', 'Échec de l’annulation du flux de retour'));
    }
  };

  const scrollToDepositReturnSection = () => {
    depositReturnSectionRef.current?.scrollIntoView({
      behavior: 'smooth',
      block: 'start',
    });
  };

  const openDepositReturnReview = () => {
    setDamageDepositReturnOpen(true);
    window.setTimeout(() => {
      scrollToDepositReturnSection();
    }, 80);
  };

  const ensureCompletedRentalPersistence = async ({
    rentalId,
    vehicleId,
    completedAt,
    vehicleStatus,
    extraRentalFields = {},
  }) => {
    const completionPayload = {
      rental_status: 'completed',
      status: 'completed',
      completed_at: completedAt,
      actual_end_date: completedAt,
      updated_at: new Date().toISOString(),
      ...extraRentalFields,
    };

    const { data: refreshedRental, error: refreshedRentalError } = await supabase
      .from('app_4c3a7a6153_rentals')
      .select('id, rental_status, status, completed_at, actual_end_date, vehicle_id')
      .eq('id', rentalId)
      .maybeSingle();

    if (refreshedRentalError) {
      throw refreshedRentalError;
    }

    const normalizedRefreshedRental = normalizeRentalLifecycleStatus(refreshedRental, rentalTimingSettings);
    if (
      !normalizedRefreshedRental ||
      normalizedRefreshedRental.rental_status !== 'completed' ||
      !normalizedRefreshedRental.completed_at
    ) {
      const { error: completionRetryError } = await supabase
        .from('app_4c3a7a6153_rentals')
        .update(completionPayload)
        .eq('id', rentalId);

      if (completionRetryError) {
        throw completionRetryError;
      }
    }

    if (vehicleId) {
      const { data: refreshedVehicle, error: refreshedVehicleError } = await supabase
        .from('saharax_0u4w4d_vehicles')
        .select('id, status')
        .eq('id', vehicleId)
        .maybeSingle();

      if (refreshedVehicleError) {
        throw refreshedVehicleError;
      }

      if (refreshedVehicle && refreshedVehicle.status !== vehicleStatus) {
        const { error: vehicleRetryError } = await supabase
          .from('saharax_0u4w4d_vehicles')
          .update({
            status: vehicleStatus,
            updated_at: completedAt,
          })
          .eq('id', vehicleId);

        if (vehicleRetryError) {
          throw vehicleRetryError;
        }
      }
    }
  };

  const maybeAutoVoidLatestExtensionOnReturn = async ({
    completedAt,
    currentRental = rental,
  }) => {
    const thresholdMinutes = Number(
      rentalTimingSettings?.extraHourThresholdMinutes
        ?? DEFAULT_RENTAL_TIMING_SETTINGS.extraHourThresholdMinutes
    );

    if (!currentRental?.id || !Number.isFinite(thresholdMinutes) || thresholdMinutes <= 0) {
      return { rental: currentRental, autoVoided: false };
    }

    const latestExtension = await ExtensionPricingService.getLatestVoidableExtension(currentRental.id);
    if (!latestExtension) {
      return { rental: currentRental, autoVoided: false };
    }

    const extensionHours = parseFloat(latestExtension.extension_hours) || 0;
    const extensionPrice = parseFloat(latestExtension.extension_price) || 0;
    const currentEndTime = new Date(
      currentRental?.rental_end_date || currentRental?.actual_end_date || ''
    ).getTime();
    const completedTime = new Date(completedAt || '').getTime();

    if (!Number.isFinite(currentEndTime) || !Number.isFinite(completedTime) || extensionHours <= 0) {
      return { rental: currentRental, autoVoided: false };
    }

    const extensionStartTime = currentEndTime - (extensionHours * 60 * 60 * 1000);
    if (completedTime < extensionStartTime || completedTime > currentEndTime) {
      return { rental: currentRental, autoVoided: false };
    }

    const elapsedMinutesInExtension = (completedTime - extensionStartTime) / 60000;
    if (elapsedMinutesInExtension > thresholdMinutes) {
      return { rental: currentRental, autoVoided: false };
    }

    await ExtensionPricingService.voidExtension(
      latestExtension.id,
      currentUser?.id,
      `Auto-voided on return after ${Math.max(0, Math.round(elapsedMinutesInExtension))} minutes of extension time`
    );

    const approvedSummary = await ExtensionPricingService.getApprovedExtensionSummary(currentRental.id);
    const nextEndDate = new Date(extensionStartTime).toISOString();
    const isHourlyRental = currentRental?.rental_type === 'hourly';
    const currentQuantityHours = parseFloat(currentRental?.quantity_hours) || 0;
    const currentQuantityDays = parseFloat(currentRental?.quantity_days) || 0;
    const nextQuantityHours = isHourlyRental
      ? Math.max(0, currentQuantityHours - extensionHours)
      : Math.max(0, (currentQuantityDays - (extensionHours / 24)) * 24);
    const nextQuantityDays = isHourlyRental
      ? nextQuantityHours
      : Math.max(0, currentQuantityDays - (extensionHours / 24));
    const currentTotalAmount = parseFloat(currentRental?.total_amount) || 0;
    const currentRemainingAmount = parseFloat(currentRental?.remaining_amount) || 0;
    const nextTotalAmount = Math.max(0, currentTotalAmount - extensionPrice);
    const nextRemainingAmount = Math.max(0, currentRemainingAmount - extensionPrice);

    const autoVoidPayload = {
      rental_end_date: nextEndDate,
      extension_count: approvedSummary.extensionCount,
      total_extended_hours: approvedSummary.totalExtendedHours,
      total_extension_price: approvedSummary.totalExtensionPrice,
      current_extension_id: approvedSummary.currentExtensionId,
      total_amount: nextTotalAmount,
      remaining_amount: nextRemainingAmount,
      quantity_hours: nextQuantityHours,
      quantity_days: nextQuantityDays,
      updated_at: new Date().toISOString(),
    };

    const { data: updatedRental, error: autoVoidError } = await updateRentalWithSchemaFallback(autoVoidPayload);
    if (autoVoidError) {
      throw autoVoidError;
    }

    setExtensions((prev) => Array.isArray(prev)
      ? prev.map((item) => (
          item.id === latestExtension.id
            ? { ...item, status: 'voided', voided_at: new Date().toISOString(), voided_by: currentUser?.id || null }
            : item
        ))
      : prev);

    toast.success(
      tr(
        `Last extension voided automatically after ${Math.max(0, Math.round(elapsedMinutesInExtension))} minutes.`,
        `Dernière prolongation annulée automatiquement après ${Math.max(0, Math.round(elapsedMinutesInExtension))} minutes.`
      )
    );

    return {
      rental: updatedRental || {
        ...currentRental,
        ...autoVoidPayload,
      },
      autoVoided: true,
      voidedExtension: latestExtension,
      elapsedMinutesInExtension,
    };
  };

  const calculateBaseHourlyOvertimeAdjustment = (currentRental = rental, completedAt) => {
    if (!currentRental?.id || !completedAt) return null;
    if (String(currentRental?.rental_status || '').toLowerCase() !== 'active') return null;
    if (String(currentRental?.rental_type || '').toLowerCase() !== 'hourly') return null;
    if (isPackagePricingEnabled(currentRental)) return null;

    const startValue = currentRental?.started_at || currentRental?.rental_start_date;
    const startTime = new Date(startValue || '');
    const closeTime = new Date(completedAt || '');
    if (!Number.isFinite(startTime.getTime()) || !Number.isFinite(closeTime.getTime())) return null;

    const preview = getLateReturnFeePreview(currentRental, closeTime.toISOString());
    if (!preview?.isLateAfterGrace || preview.expectedLateFeeAmount <= 0) return null;

    const currentLateFeeAmount = getLateFeeAmount(currentRental);
    const addedCharge = Number(Math.max(0, preview.expectedLateFeeAmount - currentLateFeeAmount).toFixed(2));
    if (addedCharge <= 0) return null;

    const currentTotal = Number(currentRental?.total_amount || 0) ||
      Number((preview.hourlyRate * preview.includedHours).toFixed(2));
    const currentRemaining = Math.max(0, Number(currentRental?.remaining_amount || 0) || 0);
    const currentGrandTotal = Number((currentTotal + currentLateFeeAmount).toFixed(2));
    const paidAmount = Math.max(0, currentGrandTotal - currentRemaining);
    const nextLateFeeAmount = Number((currentLateFeeAmount + addedCharge).toFixed(2));
    const nextGrandTotal = Number((currentTotal + nextLateFeeAmount).toFixed(2));
    const nextRemaining = Number(Math.max(0, nextGrandTotal - paidAmount).toFixed(2));

    return {
      thresholdMinutes: preview.thresholdMinutes,
      durationMinutes: preview.durationMinutes,
      minutesPastGrace: preview.minutesPastGrace,
      previousHours: preview.includedHours,
      billedHours: preview.includedHours + preview.billableLateHours,
      addedHours: preview.billableLateHours,
      hourlyRate: preview.hourlyRate,
      addedCharge,
      totalAmount: currentTotal,
      lateFeeAmount: nextLateFeeAmount,
      grandTotal: nextGrandTotal,
      remainingAmount: nextRemaining,
      paymentStatus: nextRemaining <= 0 ? 'paid' : (paidAmount > 0 ? 'partial' : 'unpaid'),
    };
  };

  const applyBaseHourlyOvertimeOnClose = async ({
    completedAt,
    currentRental = rental,
  }) => {
    const adjustment = calculateBaseHourlyOvertimeAdjustment(currentRental, completedAt);
    if (!adjustment) {
      return { rental: currentRental, adjustment: null };
    }

    const overtimePayload = {
      rental_end_date: completedAt,
      actual_end_date: completedAt,
      late_fee_amount: adjustment.lateFeeAmount,
      late_fee: adjustment.lateFeeAmount,
      remaining_amount: adjustment.remainingAmount,
      payment_status: adjustment.paymentStatus,
      updated_at: new Date().toISOString(),
    };

    const { data: updatedRental, error: overtimeError } = await updateRentalWithSchemaFallback(overtimePayload);
    if (overtimeError) {
      throw overtimeError;
    }

    const nextRental = updatedRental || {
      ...currentRental,
      ...overtimePayload,
    };

    setRental((prev) => prev ? ({
      ...prev,
      ...nextRental,
      vehicle: nextRental.vehicle || prev.vehicle,
      package: nextRental.package || prev.package,
    }) : nextRental);

    toast.success(
      tr(
        `Late return fee added automatically: +${adjustment.addedCharge.toFixed(2)} MAD.`,
        `Frais de retour tardif ajoutés automatiquement : +${adjustment.addedCharge.toFixed(2)} MAD.`
      )
    );

    return { rental: nextRental, adjustment };
  };

  const getReturnWorkflowCloseTime = (fallbackTime) => {
    const candidate = returnWorkflowBillingResult?.calculatedAt;
    const parsedCandidate = candidate ? new Date(candidate) : null;
    return parsedCandidate && Number.isFinite(parsedCandidate.getTime())
      ? parsedCandidate.toISOString()
      : fallbackTime;
  };

  const finalizeRentalCompletion = async () => {
    try {
      const actingUser = resolvedCurrentUser || currentUser || userProfile || user;
      const actorName =
        actingUser?.full_name ||
        actingUser?.name ||
        actingUser?.email ||
        user?.email ||
        'Staff';
      let latestReport = vehicleReport;
      if (vehicleReportDraft.enabled) {
        latestReport = await persistVehicleReport();
      }

      const effectiveEndingOdometer = rental?.ending_odometer ?? endOdometer ?? null;
      const effectiveEndFuelLevel = endFuelLevel ?? rental?.end_fuel_level ?? null;
      const completedAt = new Date().toISOString();
      const billingCloseTime = getReturnWorkflowCloseTime(completedAt);

      if (!effectiveEndingOdometer) {
        toast.error('Please enter ending odometer first');
        return;
      }

      if (effectiveEndFuelLevel === null || effectiveEndFuelLevel === undefined) {
        toast.error('Please record return fuel level first');
        return;
      }

      const { rental: completionRental } = await maybeAutoVoidLatestExtensionOnReturn({
        completedAt: billingCloseTime,
        currentRental: rental,
      });

      const { rental: overtimeRental, adjustment: overtimeAdjustment } = await applyBaseHourlyOvertimeOnClose({
        completedAt: billingCloseTime,
        currentRental: completionRental || rental,
      });

      const effectiveCompletionRental = overtimeRental || completionRental || rental;
      const actualReturnEndTime = billingCloseTime;
      const updateData = {
        rental_status: 'completed', 
        status: 'completed',
        completed_at: completedAt,
        completed_by: actingUser?.id || null,
        completed_by_name: actorName,
        status_changed_by: actorName,
        actual_end_date: actualReturnEndTime,
        ending_odometer: effectiveEndingOdometer,
        end_fuel_level: effectiveEndFuelLevel,
        return_location_id: selectedReturnLocationId ? Number(selectedReturnLocationId) : null,
        updated_at: new Date().toISOString()
      };
      
      // If return signature exists, update it
      if (returnSignatureUrl) {
        updateData.signature_url = returnSignatureUrl;
      }

      const { data: completedRental, error } = await updateRentalWithSchemaFallback(updateData);

      if (error) {
        console.error('❌ Database error:', error);
        throw new Error(`Database update failed: ${error.message}`);
      }
      
      // Update vehicle status
      const targetVehicleStatus = latestReport?.send_to_maintenance && latestReport?.maintenance_id ? 'maintenance' : 'available';
      if (rental.vehicle_id) {
        const { error: vehicleUpdateError } = await supabase
          .from('saharax_0u4w4d_vehicles')
          .update({ 
            status: targetVehicleStatus,
            location_id: selectedReturnLocationId ? Number(selectedReturnLocationId) : rental?.vehicle?.location_id || null,
            updated_at: completedAt
          })
          .eq('id', rental.vehicle_id);

        if (vehicleUpdateError) {
          throw vehicleUpdateError;
        }
      }

      if (completedRental) {
        setRental((prev) => ({
          ...(prev || {}),
          ...completedRental,
          vehicle: completedRental.vehicle || prev?.vehicle,
          package: completedRental.package || prev?.package,
        }));
      } else {
        setRental((prev) => prev ? ({
          ...prev,
          ...(effectiveCompletionRental || {}),
          rental_status: 'completed',
          status: 'completed',
          completed_at: completedAt,
          actual_end_date: actualReturnEndTime,
          ending_odometer: effectiveEndingOdometer,
          end_fuel_level: effectiveEndFuelLevel,
          vehicle: prev?.vehicle
            ? {
                ...prev.vehicle,
                status: targetVehicleStatus,
              }
            : prev?.vehicle,
        }) : prev);
      }

      await dispatchRentalTelegramEventSafely({
        eventType: 'rental_completed',
        actor: 'admin',
        rental: {
          id: rental.id,
          reference: effectiveCompletionRental?.rental_id || rental.rental_id || '',
          vehicle: buildRentalTelegramVehicleLabel(completedRental || effectiveCompletionRental || rental),
          customer: (completedRental || effectiveCompletionRental)?.customer_name || rental.customer_name,
          start:
            (completedRental || effectiveCompletionRental)?.started_at ||
            (completedRental || effectiveCompletionRental)?.actual_start_date ||
            rental.started_at ||
            rental.actual_start_date ||
            (completedRental || effectiveCompletionRental)?.rental_start_date ||
            rental.rental_start_date,
          end: completedAt,
          completed_at: completedAt,
          total: (completedRental || effectiveCompletionRental)?.total_amount || rental.total_amount || 0,
          amountPaid: (completedRental || effectiveCompletionRental)?.deposit_amount || rental.deposit_amount || 0,
          remaining: (completedRental || effectiveCompletionRental)?.remaining_amount || rental.remaining_amount || 0,
          total_kilometers_driven: resolveRentalTelegramDistance(
            (completedRental || effectiveCompletionRental || rental)
          ),
          completedBy: actorName,
          start_odometer:
            (completedRental || effectiveCompletionRental)?.start_odometer
            ?? rental.start_odometer
            ?? null,
          ending_odometer:
            (completedRental || effectiveCompletionRental)?.ending_odometer
            ?? effectiveEndingOdometer
            ?? rental.ending_odometer
            ?? null,
          overtime: overtimeAdjustment
            ? {
                addedHours: overtimeAdjustment.addedHours,
                addedCharge: overtimeAdjustment.addedCharge,
                thresholdMinutes: overtimeAdjustment.thresholdMinutes,
              }
            : null,
        },
      }, 'rental completed');

      await ensureCompletedRentalPersistence({
        rentalId: rental.id,
        vehicleId: rental.vehicle_id,
        completedAt,
        vehicleStatus: targetVehicleStatus,
        extraRentalFields: {
          actual_end_date: actualReturnEndTime,
          completed_by: actingUser?.id || null,
          completed_by_name: actorName,
          status_changed_by: actorName,
          ...(overtimeAdjustment ? {
            rental_end_date: actualReturnEndTime,
            late_fee_amount: overtimeAdjustment.lateFeeAmount,
            late_fee: overtimeAdjustment.lateFeeAmount,
            remaining_amount: overtimeAdjustment.remainingAmount,
            payment_status: overtimeAdjustment.paymentStatus,
          } : {}),
          ending_odometer: effectiveEndingOdometer,
          end_fuel_level: effectiveEndFuelLevel,
          signature_url: returnSignatureUrl || rental?.signature_url || null,
          return_location_id: selectedReturnLocationId ? Number(selectedReturnLocationId) : null,
        },
      });

      // Reload rental data
      await loadRentalData(true);
      
      // Broadcast real-time update for dashboard and close the shared finish workflow
      try {
        const closedWorkflowState = {
          showWorkflow: false,
          closingVideoComplete: false,
          closingDocumentComplete: true,
          endOdometerComplete: false,
          endEngineHoursComplete: false,
          endFuelComplete: false
        };

        await broadcastRentalWorkflowUpdate('finish', 'workflow_closed', {
          showWorkflow: false,
          steps: closedWorkflowState,
          rental_status: 'completed',
          completed_at: completedAt,
        });

        await supabase
          .channel('rental-updates')
          .send({
            type: 'broadcast',
            event: 'status_updated',
            payload: { 
              rental_id: rental.id, 
              rental_status: 'completed',
              completed_at: completedAt,
              updated_at: completedAt
            }
          });
      } catch (broadcastErr) {
        console.warn('Broadcast failed (non-critical):', broadcastErr);
      }
      
      // Hide workflow
      setFinishRentalSteps({
        showWorkflow: false,
        closingVideoComplete: false,
        closingDocumentComplete: true,
        endOdometerComplete: false,
        endEngineHoursComplete: false,
        endFuelComplete: false
      });
      clearFinishWorkflowState();
      setReturnWorkflowBillingResult(null);
      
      setReturnSignatureUrl(null);
      window.setTimeout(() => {
        scrollToDepositReturnSection();
      }, 180);
      
      toast.success('Rental completed successfully!');
      
    } catch (err) {
      console.error('❌ Error finalizing rental:', err);
      throw err;
    }
  };


  // Load package details for kilometer calculations
const loadPackageDetails = async (packageId = null) => {
  const pkgId = packageId || rental?.package_id;
  
  if (!pkgId) {
    if (RENTAL_DEBUG) console.log('⚠️ No package_id found');
    setPackageDetails(null);
    setIncludedKilometers(null);
    setExtraKmRate(null);
    return;
  }
  
  try {
    if (RENTAL_DEBUG) console.log('📦 Loading package with ID:', pkgId);
    
    const { data, error } = await fetchWithRetry(() =>
      supabase
        .from('app_4c3a7a6153_rental_km_packages')
        .select('*')
        .eq('id', pkgId)
        .single()
    );
    
    if (error) {
      console.error('❌ Error loading package:', error);
      setPackageDetails(null);
      setIncludedKilometers(null);
      setExtraKmRate(null);
      return;
    }
    
    if (data) {
      if (RENTAL_DEBUG) console.log('✅ Package loaded:', {
        id: data.id,
        name: data.name,
        included_kilometers: data.included_kilometers,
        extra_km_rate: data.extra_km_rate,
        fixed_amount: data.fixed_amount
      });
      
      setPackageDetails(data);
      setIncludedKilometers(getPackageTotalIncludedKilometers(rental, data));
      setExtraKmRate(parseFloat(data.extra_km_rate) || 0);
    }
  } catch (err) {
    console.error('❌ Error in loadPackageDetails:', err);
    setPackageDetails(null);
    setIncludedKilometers(null);
    setExtraKmRate(null);
  }
};

useEffect(() => {
  let isActive = true;

  const loadAvailableKmPackages = async () => {
    const vehicleModelId = rental?.vehicle?.vehicle_model?.id || rental?.vehicle?.vehicle_model_id;
    if (!vehicleModelId) {
      setAvailableKmPackages([]);
      return;
    }

    try {
      const { data, error } = await fetchWithRetry(() => {
        let query = supabase
          .from('app_4c3a7a6153_rental_km_packages')
          .select('*, rate_types(name)')
          .eq('vehicle_model_id', vehicleModelId)
          .eq('is_active', true);

        if (rental?.rental_type === 'hourly') {
          query = query.or('rate_type_id.eq.1,rate_type_id.is.null');
        } else if (rental?.rental_type === 'daily') {
          query = query.or('rate_type_id.eq.2,rate_type_id.is.null');
        }

        return query.order('included_kilometers', { ascending: true });
      });

      if (!isActive) return;
      if (error) {
        console.warn('⚠️ Failed to load available kilometer packages:', error);
        setAvailableKmPackages([]);
        return;
      }

      setAvailableKmPackages(Array.isArray(data) ? data : []);
    } catch (loadError) {
      if (!isActive) return;
      console.warn('⚠️ Failed to load available kilometer packages:', loadError);
      setAvailableKmPackages([]);
    }
  };

  loadAvailableKmPackages();

  return () => {
    isActive = false;
  };
}, [rental?.rental_type, rental?.vehicle?.vehicle_model?.id, rental?.vehicle?.vehicle_model_id]);

// Load fuel charge settings — reads from fuel_pricing table by vehicle model
const loadFuelChargeSettings = async () => {
  try {
    const modelId = rental?.vehicle?.vehicle_model?.id || rental?.vehicle?.vehicle_model_id;
    if (!modelId) return;

    const type = rental?.rental_type || 'daily';
    const { data, error } = await supabase
      .from('fuel_pricing')
      .select('price_per_line, hourly_price_per_line, daily_price_per_line')
      .eq('model_id', modelId)
      .single();

    if (error && error.code !== 'PGRST116') {
      console.error('Error loading fuel pricing:', error);
      return;
    }

    if (data) {
      const price = type === 'hourly'
        ? parseFloat(data.hourly_price_per_line ?? data.price_per_line) || 0
        : parseFloat(data.daily_price_per_line ?? data.price_per_line) || 0;
      setFuelPricePerLine(price);
    }
  } catch (error) {
    console.error('Error loading fuel charge settings:', error);
  }
};


  // ✅ REMOVED: Duplicate loadPackageDetails useEffect - already called inside loadRentalData()
  // Package loading is handled in loadRentalData() when rental data is fetched

  // Clear tier pricing when package is loaded
  useEffect(() => {
    if (packageDetails) {
      if (RENTAL_DEBUG) console.log('📦 Package loaded, clearing tier pricing');
      setTierPricingBreakdown(null);
    }
  }, [packageDetails]);

  // Debug useEffect removed to reduce unnecessary re-renders and console spam


  const resolveEndOdometerValue = (rawValue = null) => {
    const candidateValue = [
      rawValue,
      endOdometerPromptInputRef.current?.value,
      endOdometerEditInputRef.current?.value,
      endOdometerEditValue,
      endOdometer,
    ].find((value) => value !== null && value !== undefined && String(value).trim() !== '');

    const normalizedValue = String(candidateValue ?? '').replace(/,/g, '.').trim();
    const parsedValue = parseFloat(normalizedValue);

    return { normalizedValue, parsedValue };
  };

  const resolveKilometerPackageApplicationForDistance = useCallback(
    (totalDistance) => selectAppliedKilometerPackage({
      rental,
      bookedPackage: getRentalKilometerPackage(rental, packageDetails),
      packageDetails,
      availablePackages: availableKmPackages,
      gracePeriodMinutes: rentalTimingSettings?.graceMinutes ?? DEFAULT_RENTAL_TIMING_SETTINGS.graceMinutes,
      totalDistance,
      allowAutoUpgrade: autoPackageUpgradeEnabled,
    }),
    [autoPackageUpgradeEnabled, availableKmPackages, packageDetails, rental, rentalTimingSettings?.graceMinutes]
  );

  const [isSavingAutoPackageUpgradePreference, setIsSavingAutoPackageUpgradePreference] = useState(false);
  const canToggleAutoPackageUpgrade =
    hasBookedKilometerPackage &&
    autoMatchedPackageDiffers &&
    (
      ['owner', 'admin', 'employee', 'staff', 'support', 'business_owner', 'guide'].includes(currentUserRole) ||
      hasRentalManagementAccess
    );

  const handleToggleAutoPackageUpgrade = useCallback(async (nextEnabled) => {
    if (!rental?.id || !bookedKilometerPackage || isSavingAutoPackageUpgradePreference) return;

    setIsSavingAutoPackageUpgradePreference(true);
    try {
      const totalDistance = Math.max(0, Number(rental?.total_kilometers_driven || rental?.total_distance || 0) || 0);
      const packageApplication = selectAppliedKilometerPackage({
        rental,
        bookedPackage: bookedKilometerPackage,
        packageDetails,
        availablePackages: availableKmPackages,
        gracePeriodMinutes: rentalTimingSettings?.graceMinutes ?? DEFAULT_RENTAL_TIMING_SETTINGS.graceMinutes,
        totalDistance,
        allowAutoUpgrade: nextEnabled,
      });
      const appliedPackage = packageApplication.appliedPackage || bookedKilometerPackage || null;
      const packagePrice = Math.max(0, Number(packageApplication.appliedPrice || 0) || 0);
      const overageCharge = Math.max(0, Number(packageApplication.overageCharge || 0) || 0);
      const appliedLimit = Number.isFinite(packageApplication.appliedLimit)
        ? Math.max(0, Number(packageApplication.appliedLimit || 0))
        : null;
      const bookedLimit = getConfiguredPackageTotalIncludedKilometers(rental, bookedKilometerPackage);
      const persistedBookedLimit = Number.isFinite(bookedLimit) && bookedLimit > 0
        ? bookedLimit
        : (rental?.package_total_included_km ?? null);
      const extraRate = Math.max(0, Number(packageApplication.appliedExtraRate || 0) || 0);
      const rentalSubtotal =
        packagePrice +
        overageCharge +
        Math.max(0, Number(rentalBillingSummary.extensionFees || 0) || 0);
      const grossGrandTotal =
        rentalSubtotal +
        Math.max(0, Number(rentalBillingSummary.fuelChargeAmount || 0) || 0) +
        Math.max(0, Number(rentalBillingSummary.impoundChargeAmount || 0) || 0) +
        Math.max(0, Number(rentalBillingSummary.maintenanceChargeAmount || 0) || 0) +
        Math.max(0, Number(rentalBillingSummary.transportFeeAmount || 0) || 0);
      const companyDiscountAmount = Math.max(0, Number(rentalBillingSummary.companyDiscountAmount || 0) || 0);
      const finalGrandTotal = Math.max(0, grossGrandTotal - companyDiscountAmount);
      const customerPaidAmount = Math.max(
        0,
        Number(rentalBillingSummary.customerPaidAmount || rentalBillingSummary.depositPaid || rental?.deposit_amount || 0) || 0
      );
      const remainingAmount = Math.max(0, finalGrandTotal - customerPaidAmount);
      const existingMeta = parsePriceOverrideMeta(rental?.price_override_reason) || {};
      const nextMeta = {
        ...existingMeta,
        autoPackageUpgradeEnabled: Boolean(nextEnabled),
        autoPackageUpgradeEditedAt: new Date().toISOString(),
        autoPackageUpgradeEditedById: resolvedCurrentUser?.id || currentUser?.id || null,
        autoPackageUpgradeEditedByName:
          resolvedCurrentUser?.full_name ||
          resolvedCurrentUser?.name ||
          resolvedCurrentUser?.email ||
          currentUser?.full_name ||
          currentUser?.name ||
          currentUser?.email ||
          null,
      };

      const updateData = {
        total_amount: rentalSubtotal,
        remaining_amount: remainingAmount,
        payment_status: remainingAmount > 0 ? (customerPaidAmount > 0 ? 'partial' : 'unpaid') : 'paid',
        overage_charge: overageCharge,
        included_kilometers_applied: appliedLimit,
        package_total_included_km: persistedBookedLimit,
        extra_km_rate_applied: appliedPackage ? extraRate : null,
        unit_price: appliedPackage ? Number(getPackageRatePerUnit(rental, appliedPackage) || rental.unit_price || 0) : rental.unit_price,
        price_override_reason: JSON.stringify(nextMeta),
        updated_at: new Date().toISOString(),
      };

      const { error: updateError } = await supabase
        .from('app_4c3a7a6153_rentals')
        .update(updateData)
        .eq('id', rental.id);

      if (updateError) throw updateError;

      setRental((prev) => prev ? {
        ...prev,
        ...updateData,
      } : prev);

      toast.success(
        nextEnabled
          ? tr('Auto package upgrade enabled and totals recalculated.', 'Surclassement auto activé et totaux recalculés.')
          : tr('Auto package upgrade disabled. Original package restored and overage recalculated.', 'Surclassement auto désactivé. Le forfait initial est rétabli et le dépassement recalculé.')
      );
      await loadRentalData(true);
    } catch (error) {
      console.error('Failed to toggle auto package upgrade:', error);
      toast.error(`${tr('Could not update package pricing mode', 'Impossible de mettre à jour le mode tarifaire du forfait')}: ${error.message}`);
    } finally {
      setIsSavingAutoPackageUpgradePreference(false);
    }
  }, [
    availableKmPackages,
    bookedKilometerPackage,
    currentUser,
    isSavingAutoPackageUpgradePreference,
    packageDetails,
    rental,
    rentalBillingSummary.companyDiscountAmount,
    rentalBillingSummary.customerPaidAmount,
    rentalBillingSummary.depositPaid,
    rentalBillingSummary.extensionFees,
    rentalBillingSummary.fuelChargeAmount,
    rentalBillingSummary.impoundChargeAmount,
    rentalBillingSummary.maintenanceChargeAmount,
    rentalBillingSummary.transportFeeAmount,
    rentalTimingSettings?.graceMinutes,
    resolvedCurrentUser,
  ]);

  const handleEndOdometerSubmit = async (rawValue = null) => {
    const { normalizedValue, parsedValue: endOdometerValue } = resolveEndOdometerValue(rawValue);

    if (!Number.isFinite(endOdometerValue) || endOdometerValue <= 0) {
      toast.error(`Please enter a valid ending odometer reading. Received: ${normalizedValue || '(empty)'}`);
      return;
    }
    const startOdometerValue = resolveDisplayedStartingOdometer(rental, startOdometer);

    if (endOdometerValue < startOdometerValue) {
      toast.error(`Invalid: Ending odometer (${endOdometerValue} km) cannot be less than starting (${startOdometerValue} km).`);
      return;
    }

    setIsProcessingEndOdometer(true);
    try {
      // Calculate total distance
      const totalDistance = endOdometerValue - startOdometerValue;
      
      const pricingSummary = calculateSimpleRentalPricing({
        startTime: rental?.started_at || rental?.rental_start_date,
        endTime: getRentalEffectiveEndTime(rental),
        gracePeriodMinutes: rentalTimingSettings?.graceMinutes ?? DEFAULT_RENTAL_TIMING_SETTINGS.graceMinutes,
        hourlyRate: getRentalHourlyRate(rental),
        totalKmUsed: totalDistance,
        packages: availableKmPackages.length > 0 ? availableKmPackages : [rental?.package, packageDetails].filter(Boolean),
        usePackagePricing: isPackagePricingEnabled(rental),
        rentalType: rental?.rental_type,
        originalPackage: getRentalKilometerPackage(rental, packageDetails),
        durationUnits: getRentalActualDurationUnits(rental) || getRentalDurationUnits(rental) || 1,
      });
      const packageApplication = resolveKilometerPackageApplicationForDistance(totalDistance);
      const pkg = packageApplication.appliedPackage || null;
      const includedKm = Number.isFinite(packageApplication.appliedLimit)
        ? Number(packageApplication.appliedLimit || 0)
        : null;
      const extraRate = packageApplication.appliedExtraRate;
      const extraKms = packageApplication.overageKm;
      const overageCharge = packageApplication.overageCharge;
      
      if (RENTAL_DEBUG) console.log('📊 Odometer calculation:', {
        startOdometer: startOdometerValue,
        endOdometer: endOdometerValue,
        totalDistance,
        includedKm,
        extraKms,
        extraRate,
        overageCharge
      });
      
      const originalPrice = Number(packageApplication.appliedPrice || pricingSummary?.totalPrice || 0);
      const extensionFees = totalExtensionFees || 0;
      const fuelChargeAmount = getEffectiveFuelChargeAmount({ rental, endFuelLevel, fuelCharge, fuelChargeEnabled });
      const maintenanceChargeAmount = getLinkedMaintenanceChargeAmount();
      const finalTotal = originalPrice + overageCharge + extensionFees + fuelChargeAmount + maintenanceChargeAmount;

      // Update rental with all calculated values
      const { error: updateError } = await supabase
        .from('app_4c3a7a6153_rentals')
        .update({
          ending_odometer: endOdometerValue,
          overage_charge: overageCharge, // This is the source of truth
          total_distance: totalDistance,
          total_kilometers_driven: totalDistance,
          included_kilometers_applied: pkg ? includedKm : null,
          extra_km_rate_applied: pkg ? extraRate : null,
          unit_price: pkg ? Number(getPackageRatePerUnit(rental, pkg) || rental.unit_price || 0) : rental.unit_price,
          total_amount: finalTotal,
          remaining_amount: Math.max(0, finalTotal - (parseFloat(rental.deposit_amount) || 0)),
          updated_at: new Date().toISOString()
        })
        .eq('id', rental.id);

      if (updateError) throw updateError;

      // Update vehicle odometer
      if (rental.vehicle_id) {
        const { error: vehicleError } = await supabase
          .from('saharax_0u4w4d_vehicles')
          .update({ 
            current_odometer: endOdometerValue,
            updated_at: new Date().toISOString()
          })
          .eq('id', rental.vehicle_id);

        if (vehicleError) {
          console.error('Failed to update vehicle odometer:', vehicleError);
        }
      }

      // Update local state
      setRental(prev => ({
        ...prev,
        ending_odometer: endOdometerValue,
        overage_charge: overageCharge,
        total_distance: totalDistance,
        total_kilometers_driven: totalDistance,
        included_kilometers_applied: pkg ? includedKm : null,
        extra_km_rate_applied: pkg ? extraRate : null,
        unit_price: pkg ? Number(getPackageRatePerUnit(prev, pkg) || prev.unit_price || 0) : prev.unit_price,
        total_amount: finalTotal,
        remaining_amount: Math.max(0, finalTotal - (parseFloat(prev.deposit_amount) || 0))
      }));

      setShowEndOdometerPrompt(false);
      setEndOdometer('');
      
      // Update workflow completion
      setFinishRentalSteps(prev => ({
        ...prev,
        endOdometerComplete: true
      }));
      await broadcastRentalWorkflowUpdate('finish', 'end_odometer', {
        showWorkflow: true,
        steps: {
          ...buildFinishWorkflowState(),
          endOdometerComplete: true,
        },
      });
      
      const overageMessage = !pkg
        ? `\nNo kilometer package applied`
        : packageApplication.upgraded
        ? `\n✅ Auto-upgraded to ${getKilometerPackageName(packageApplication.appliedPackage, 'upgraded package')} (${Number.isFinite(packageApplication.appliedLimit) ? `${packageApplication.appliedLimit} km` : 'unlimited'} limit)`
        : overageCharge > 0 
        ? `
ℹ️ Highest package reached: ${extraKms} km above ${includedKm} km`
        : `
✅ Best package selected (${includedKm} km limit)`;
      
      toast.success(`Ending odometer saved: ${endOdometerValue} km

Distance: ${totalDistance.toFixed(2)} km • ${pricingSummary?.billedHours || 0} billed hour(s)${overageMessage}`);
      
    } catch (err) {
      console.error('❌ Error saving ending odometer:', err);
      toast.error(`Failed to save ending odometer. Error: ${err.message}`);
    } finally {
      setIsProcessingEndOdometer(false);
    }
  };

  // Handle editing the end odometer
