        if (video.readyState >= 2) {
          if (RENTAL_DEBUG) console.log('✅ Video ready, dimensions:', video.videoWidth, 'x', video.videoHeight);
          resolve();
        } else {
          video.onloadeddata = () => {
            if (RENTAL_DEBUG) console.log('✅ Video loadeddata event fired');
            resolve();
          };
          // Fallback timeout
          setTimeout(resolve, 2000);
        }
