      actionLabel: assignVehicleStepComplete
        ? tr('Assigned', 'Attribué')
        : tr('Assign vehicle', 'Attribuer'),
      onAction: openReplaceVehicleDialog,
      disabled: isStartWorkflowSoftLocked || assignVehicleStepComplete,
