                  <div className="flex justify-between pt-2 border-t font-bold">
                    <span>{tr('Amount Returned:', 'Montant rendu :')}</span>
                    <span className="text-green-600">{formatCurrency(rental.deposit_return_amount || 0)} MAD</span>
                  </div>
